// src/pages/ExpensesPage.js
import React, { useState, useEffect } from "react";
import { useApp } from "../context/AppContext";
import { expenseAPI } from "../utils/api";
import ExpenseModal from "../components/modals/ExpenseModal";
import DeleteModal from "../components/modals/DeleteModal";
import toast from "react-hot-toast";
import { formatDate } from "../utils/khmerUtils";

const CATEGORIES = [
  "food",
  "drink",
  "fruit",
  "transport",
  "clothing",
  "health",
  "entertainment",
  "education",
  "utilities",
  "shopping",
  "other",
];
const MONTHS_EN = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];

export default function ExpensesPage() {
  const { t, formatAmount, formatNum, language } = useApp();
  const [expenses, setExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addModal, setAddModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [deleteId, setDeleteId] = useState(null);
  const [deleting, setDeleting] = useState(false);
  const [filterCat, setFilterCat] = useState("");
  const [filterMonth, setFilterMonth] = useState("");
  const [filterYear, setFilterYear] = useState("");
  const [search, setSearch] = useState("");

  const loadExpenses = async () => {
    setLoading(true);
    try {
      const params = {};
      if (filterCat) params.category = filterCat;
      if (filterMonth && filterYear) {
        params.month = filterMonth;
        params.year = filterYear;
      } else if (filterYear) params.year = filterYear;
      const res = await expenseAPI.getAll(params);
      setExpenses(res.data || []);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadExpenses();
  }, [filterCat, filterMonth, filterYear]);

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await expenseAPI.delete(deleteId);
      toast.success(t("deletedSuccess"));
      setDeleteId(null);
      loadExpenses();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setDeleting(false);
    }
  };

  const filtered = expenses.filter(
    (e) => !search || e.itemName?.toLowerCase().includes(search.toLowerCase()),
  );

  const totalUSD = filtered.reduce((s, e) => s + (e.amountUSD || 0), 0);

  const [viewMode, setViewMode] = useState("table");
  // "table" | "grid" | "rows"

  return (
    <div className="space-y-5 animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1
            className="font-display font-bold text-2xl"
            style={{ color: "var(--text-primary)" }}
          >
            💸 {t("expenses")}
          </h1>
          <p
            className="text-sm mt-0.5"
            style={{ color: "var(--text-secondary)" }}
          >
            {t("total")}: {formatAmount(totalUSD)} ·{" "}
            {formatNum(filtered.length)} {t("items")}
          </p>
        </div>
        <button
          className="btn btn-primary"
          onClick={() => {
            setEditData(null);
            setAddModal(true);
          }}
        >
          + {t("addNew")}
        </button>
      </div>

      {/* Filters */}
      <div className="card p-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <input
            type="text"
            placeholder={t("search")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="form-input"
          />
          <select
            value={filterCat}
            onChange={(e) => setFilterCat(e.target.value)}
            className="form-input"
          >
            <option value="">{t("allCategories")}</option>
            {CATEGORIES.map((c) => (
              <option key={c} value={c}>
                {t(c)}
              </option>
            ))}
          </select>
          <select
            value={filterMonth}
            onChange={(e) => setFilterMonth(e.target.value)}
            className="form-input"
          >
            <option value="">{t("allMonths")}</option>
            {MONTHS_EN.map((m, i) => (
              <option key={m} value={i + 1}>
                {m}
              </option>
            ))}
          </select>
          <select
            value={filterYear}
            onChange={(e) => setFilterYear(e.target.value)}
            className="form-input"
          >
            <option value="">All Years</option>
            {[2024, 2025, 2026, 2027, 2028].map((y) => (
              <option key={y} value={y}>
                {y}
              </option>
            ))}
          </select>
        </div>
      </div>

      <div className="flex gap-1 bg-[var(--bg-primary)] p-1 rounded-lg border border-[var(--border)]">
        {["table", "grid", "rows"].map((mode) => (
          <button
            key={mode}
            onClick={() => setViewMode(mode)}
            className={`px-3 py-1 text-xs rounded-md font-semibold transition ${
              viewMode === mode
                ? "bg-primary-500 text-white"
                : "text-[var(--text-secondary)]"
            }`}
          >
            {mode === "table" && "📊"}
            {mode === "grid" && "🔳"}
            {mode === "rows" && "📋"}
          </button>
        ))}
      </div>

      {/* Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="p-8 text-center text-sm text-[var(--text-secondary)]">
            {t("loading")}
          </div>
        ) : filtered.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-4xl mb-3">🧾</div>
            <div className="font-semibold text-[var(--text-secondary)]">
              {t("noExpenses")}
            </div>
          </div>
        ) : (
          <>
            {/* ================= TABLE VIEW ================= */}
            {viewMode === "table" && (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="bg-[var(--bg-primary)] border-b border-[var(--border)]">
                      {[t("itemName"), t("amount"), t("date"), ""].map(
                        (h, i) => (
                          <th
                            key={i}
                            className="px-4 py-3 text-left text-xs font-bold uppercase text-[var(--text-secondary)]"
                          >
                            {h}
                          </th>
                        ),
                      )}
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.map((e) => (
                      <tr
                        key={e._id}
                        className="border-b border-[var(--border)] hover:bg-[var(--bg-primary)]"
                      >
                        <td className="px-4 py-3">
                          <div className="font-semibold">{e.itemName}</div>
                          <div className="text-xs text-[var(--text-secondary)]">
                            {t(e.category)}
                          </div>
                        </td>
                        <td className="px-4 py-3 font-bold text-primary-500">
                          {formatAmount(e.amountUSD, e.amountKHR)}
                        </td>
                        <td className="px-4 py-3 text-sm text-[var(--text-secondary)]">
                          {formatDate(e.date, language, "medium")}
                        </td>
                        <td className="px-4 py-3 text-right">✏️ 🗑️</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            {/* ================= GRID VIEW ================= */}
            {viewMode === "grid" && (
              <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4 p-4">
                {filtered.map((e) => (
                  <div
                    key={e._id}
                    className="p-4 rounded-xl border border-[var(--border)] bg-[var(--bg-primary)] space-y-2"
                  >
                    <div className="flex justify-between items-start">
                      <div className="text-xl">{e.categoryEmoji}</div>
                      <div className="text-xs text-[var(--text-secondary)]">
                        {formatDate(e.date, language, "medium")}
                      </div>
                    </div>

                    <div className="font-semibold">{e.itemName}</div>

                    <div className="text-primary-500 font-bold">
                      {formatAmount(e.amountUSD, e.amountKHR)}
                    </div>

                    <div className="text-xs text-[var(--text-secondary)]">
                      {t(e.category)}
                    </div>

                    <div className="flex justify-end gap-2 pt-2">✏️ 🗑️</div>
                  </div>
                ))}
              </div>
            )}

            {/* ================= ROWS (MOBILE STYLE) ================= */}
            {viewMode === "rows" && (
              <div className="divide-y divide-[var(--border)]">
                {filtered.map((e) => (
                  <div key={e._id} className="p-4 flex items-center gap-3">
                    <div className="text-2xl">{e.categoryEmoji}</div>

                    <div className="flex-1 min-w-0">
                      <div className="font-semibold truncate">{e.itemName}</div>
                      <div className="text-xs text-[var(--text-secondary)]">
                        {formatDate(e.date, language, "medium")}
                      </div>
                    </div>

                    <div className="text-right">
                      <div className="font-bold text-primary-500">
                        {formatAmount(e.amountUSD, e.amountKHR)}
                      </div>
                      <div className="text-xs text-[var(--text-secondary)]">
                        {t(e.category)}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </div>

      <ExpenseModal
        isOpen={addModal}
        onClose={() => {
          setAddModal(false);
          setEditData(null);
        }}
        editData={editData}
        onSuccess={loadExpenses}
      />
      <DeleteModal
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDelete}
        loading={deleting}
      />
    </div>
  );
}
